// ---------- Field geometry (SVG viewBox 0 0 400 380) ----------
const POS = {
  home:   { x: 200, y: 330 },
  first:  { x: 316, y: 214 },
  second: { x: 200, y: 98 },
  third:  { x: 84,  y: 214 },
  P:  { x: 200, y: 218 },
  C:  { x: 200, y: 358 },
  "1B": { x: 296, y: 192 },
  "2B": { x: 250, y: 152 },
  "SS": { x: 150, y: 152 },
  "3B": { x: 104, y: 192 },
  LF: { x: 90,  y: 65 },
  CF: { x: 200, y: 40 },
  RF: { x: 310, y: 65 },
};

const POS_NAME = {
  P: "pitcher", C: "catcher",
  "1B": "first baseman", "2B": "second baseman",
  SS: "shortstop", "3B": "third baseman",
  LF: "left fielder", CF: "center fielder", RF: "right fielder",
};

const OUTFIELDERS = new Set(["LF","CF","RF"]);

// Replace position abbreviations with full names in human-readable text.
// Used for both visible prompts and spoken voice.
function expandPositions(text) {
  if (!text) return text;
  return text
    .replace(/\bSS\b/g, "shortstop")
    .replace(/\b2B\b/g, "second baseman")
    .replace(/\b3B\b/g, "third baseman")
    .replace(/\b1B\b/g, "first baseman")
    .replace(/\bLF\b/g, "left fielder")
    .replace(/\bCF\b/g, "center fielder")
    .replace(/\bRF\b/g, "right fielder");
}

// Midpoint between two positions (for cutoff visual placement)
const midpoint = (a, b) => ({ x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 });

// Displayed position for a fielder, accounting for cutoff movement.
// SS shifts toward LF/CF when those are the hit zones; 2B shifts toward RF.
function displayedPos(fielder, sc) {
  if (!sc || !fielder || !POS[fielder]) return POS[fielder];
  if (sc.mode === "popup") return POS[fielder];
  const ballAt = sc.ballAt;
  if (fielder === "SS" && (ballAt === "LF" || ballAt === "CF")) {
    // Sit the SS on the cutoff line toward the ball, but nudge left so the
    // tappable SS icon doesn't crowd the 2B / second-base area.
    const mid = midpoint(POS.SS, POS[ballAt]);
    return { x: mid.x - 28, y: mid.y };
  }
  if (fielder === "2B" && ballAt === "RF") {
    const mid = midpoint(POS["2B"], POS.RF);
    return { x: mid.x + 28, y: mid.y };
  }
  return POS[fielder];
}

// Stable hash from a string seed (for deterministic MC option ordering)
function strHash(s) {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = ((h << 5) - h + s.charCodeAt(i)) | 0;
  return Math.abs(h);
}

// Auto-generate multiple-choice options for outfielder cover scenarios.
// These are "back up X" plays with no good tap target — MC is the right UX.
function generateMCOptions(sc) {
  if (sc.mc) return sc.mc; // explicit override per scenario

  // Only outfielder COVER scenarios get auto-MC
  if (sc.mode !== "cover") return null;
  if (!OUTFIELDERS.has(sc.position)) return null;

  // Build the correct label
  let correctLabel;
  if (sc.mcCorrect) {
    correctLabel = sc.mcCorrect;
  } else if (sc.correct === "stay") {
    correctLabel = "Stay where you are — too far to back up";
  } else if (sc.correct === "P") {
    correctLabel = "Back up the pitcher behind the play";
  } else if (["first","second","third","home"].includes(sc.correct)) {
    const baseName = sc.correct === "home" ? "home plate" : `${sc.correct} base`;
    correctLabel = `Back up the throw to ${baseName}`;
  } else {
    const posName = POS_NAME[sc.correct] || sc.correct;
    correctLabel = `Back up the ${posName} in case the ball gets by them`;
  }

  // Standard distractors
  const POOL = [
    "Throw to first base",
    "Cover second base",
    "Stand still and watch the play",
    "Run home to back up the catcher",
    "Throw home",
    "Run in and cover the pitcher's mound",
  ];
  const dist = POOL.filter((d) => d !== correctLabel).slice(0, 2);

  // Deterministic correct position based on scenario id
  const seed = (sc.id || sc.prompt || "x") + sc.position;
  const correctPos = strHash(seed) % 3;

  const opts = [...dist];
  opts.splice(correctPos, 0, correctLabel);
  return opts.map((label, i) => ({ label, correct: i === correctPos }));
}

