// ============================================================
// SUPPLEMENTARY SCENARIOS — fills each (position × difficulty)
// to at least 10 plays. Each is a real teaching scenario, not filler.
// Compact helpers to keep this readable.
// ============================================================
const T = (pos, diff, baseSit, ballAt, correct, prompt, why, hint, variant) => {
  const bases = ["first","second","third","home"];
  const correctArr = Array.isArray(correct) ? correct : [correct];
  // If any correct answer is a fielder (cutoff like SS or 2B), add it to targets
  const extraTargets = correctArr.filter((c) => !bases.includes(c));
  const targets = [...bases, ...extraTargets];
  return SC({ position: pos, difficulty: diff, baseSit, mode: "throw", ballAt,
    targets, correct, prompt, why, hint, variant });
};

const CV = (pos, diff, baseSit, ballAt, you, correct, prompt, why, hint, targets) =>
  SC({ position: pos, difficulty: diff, baseSit, mode: "cover", ballAt, you,
    targets: targets || ["first","second","third","home"], correct, prompt, why, hint });

const PU = (pos, diff, popupAt, candidates, correct, prompt, why, hint) =>
  SC({ position: pos, difficulty: diff, mode: "popup", popupAt, candidates, correct, prompt, why, hint });

// ============================================================
// BASE RUNNERS MODULE
// Teaches what to do AS A RUNNER. Answers are conceptual → multiple choice.
// BR(diff, runnerAt, prompt, options[], correctIndex, why, hint)
//   runnerAt: which base the "YOU" runner starts on ("first"|"second"|"third"|"home"=batter)
//   options:  array of answer strings
//   correctIndex: index of the right option
// ============================================================
const BR = (diff, runnerAt, prompt, options, correctIndex, why, hint) =>
  SC({
    position: "RUNNER", difficulty: diff, mode: "baserun", runnerAt,
    prompt, why, hint,
    mc: options.map((label, i) => ({ label, correct: i === correctIndex })),
  });

