// ============================================================
// CINEMATIC BALL ANIMATION
// AnimatedBall animates along a path (from → to) with a parabolic arc,
// fading trail, and a "puff" landing.  Type "hit" has a higher, slower
// arc.  Type "throw" is fast and flat.  Type "rocket" is hardest+fastest.
// ============================================================
function AnimatedBall({ path, onArrive }) {
  // path: { from:{x,y}, to:{x,y}, type:"hit"|"throw"|"rocket"|"popup", id }
  const [tick, setTick] = useState(0);
  const startRef = useRef(0);
  const rafRef = useRef(0);
  const trailRef = useRef([]);

  // Restart animation when path changes
  useEffect(() => {
    if (!path) return;
    cancelAnimationFrame(rafRef.current);
    startRef.current = performance.now();
    trailRef.current = [];
    const dur = path.type === "rocket" ? 320
      : path.type === "throw" ? 520
      : path.type === "popup" ? 1
      : 780; // hit
    const loop = (now) => {
      const t = Math.min(1, (now - startRef.current) / dur);
      setTick(t);
      if (t < 1) rafRef.current = requestAnimationFrame(loop);
      else if (onArrive) onArrive();
    };
    rafRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(rafRef.current);
    // eslint-disable-next-line
  }, [path && path.id]);

  if (!path) return null;
  const { from, to, type } = path;

  // Parabolic arc: y dips up (negative) in the middle.
  // Arc height depends on type: hits arc high, throws arc low, rockets nearly flat.
  const arcHeight = type === "hit" ? 70 : type === "throw" ? 25 : type === "rocket" ? 12 : 0;
  const t = tick;
  const x = from.x + (to.x - from.x) * t;
  // Ease distance, then add a sinusoidal arc lift
  const linearY = from.y + (to.y - from.y) * t;
  const lift = -Math.sin(t * Math.PI) * arcHeight;
  const y = linearY + lift;

  // Trail: keep last few positions
  if (t < 1) {
    trailRef.current.push({ x, y, t });
    if (trailRef.current.length > 8) trailRef.current.shift();
  }

  return (
    <g style={{ pointerEvents: "none" }}>
      {/* Motion trail */}
      {trailRef.current.map((p, i) => {
        const age = trailRef.current.length - i;
        const op = Math.max(0, 0.45 - age * 0.06);
        const r = Math.max(2, 9 - age * 0.7);
        return <circle key={i} cx={p.x} cy={p.y} r={r} fill="#fff" opacity={op} />;
      })}
      {/* Glow */}
      <circle cx={x} cy={y} r="14" fill="#fde68a" opacity={type === "rocket" ? 0.4 : 0.22} />
      {/* Ball */}
      <circle cx={x} cy={y} r="9" fill="#fff" stroke="#1e293b" strokeWidth="1.5" />
      <path d={`M${x-4} ${y-5} Q${x-7} ${y} ${x-4} ${y+5} M${x+4} ${y-5} Q${x+7} ${y} ${x+4} ${y+5}`}
        stroke="#dc2626" strokeWidth="1.5" fill="none" />
      {/* Spin lines when fast */}
      {type === "rocket" && (
        <>
          <line x1={x-12} y1={y-3} x2={x-7} y2={y-3} stroke="#fff" strokeWidth="2" opacity="0.7" />
          <line x1={x-12} y1={y} x2={x-7} y2={y} stroke="#fff" strokeWidth="2" opacity="0.7" />
          <line x1={x-12} y1={y+3} x2={x-7} y2={y+3} stroke="#fff" strokeWidth="2" opacity="0.7" />
        </>
      )}
    </g>
  );
}

// Landing puff: shows briefly after the ball arrives at its destination
function LandingPuff({ x, y, show }) {
  const [tick, setTick] = useState(1);
  useEffect(() => {
    if (!show) return;
    setTick(0);
    const start = performance.now();
    let raf;
    const loop = (now) => {
      const t = Math.min(1, (now - start) / 400);
      setTick(t);
      if (t < 1) raf = requestAnimationFrame(loop);
    };
    raf = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(raf);
  }, [show, x, y]);

  if (!show || tick >= 1) return null;
  const scale = 0.6 + tick * 1.4;
  const op = 0.7 * (1 - tick);
  return (
    <g style={{ pointerEvents: "none", transform: `translate(${x}px,${y}px) scale(${scale})`,
      transformOrigin: `${x}px ${y}px` }} opacity={op}>
      <circle r="14" fill="none" stroke="#fff" strokeWidth="2.5" />
      <circle r="9" fill="none" stroke="#fbbf24" strokeWidth="2" opacity="0.7" />
    </g>
  );
}

// Running pitcher: animates a little pitcher figure from the mound to the ball,
// then "catches" it. Used in the pitcher rehearse step (tap the ball).
function RunningPitcher({ run, onArrive }) {
  const [tick, setTick] = useState(0);
  const rafRef = useRef(0);
  useEffect(() => {
    if (!run) return;
    setTick(0);
    const start = performance.now();
    const dur = 650;
    const loop = (now) => {
      const t = Math.min(1, (now - start) / dur);
      setTick(t);
      if (t < 1) rafRef.current = requestAnimationFrame(loop);
      else if (onArrive) onArrive();
    };
    rafRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(rafRef.current);
    // eslint-disable-next-line
  }, [run && run.id]);

  if (!run) return null;
  const { from, to } = run;
  const t = tick;
  const x = from.x + (to.x - from.x) * t;
  const y = from.y + (to.y - from.y) * t;
  const bounce = t < 1 ? -Math.abs(Math.sin(t * Math.PI * 5)) * 3 : 0;
  const faceLeft = to.x < from.x;
  const flip = faceLeft ? -1 : 1;

  return (
    <g style={{ pointerEvents: "none" }} transform={`translate(${x}, ${y + bounce})`}>
      <ellipse cx="0" cy="14" rx="7" ry="2" fill="rgba(0,0,0,0.18)" />
      <g transform={`scale(${flip},1)`}>
        <path d="M-4,-13 Q0,-16 4,-13 L4,-11 L-4,-11 Z" fill="#dc2626" stroke="#7f1d1d" strokeWidth="0.6" />
        <path d="M4,-12 L8,-11.5" stroke="#7f1d1d" strokeWidth="1.2" />
        <circle cx="0" cy="-8" r="3.2" fill="#fcd9b6" stroke="#c98a4c" strokeWidth="0.5" />
        <path d="M-3.5,-5 Q-4.5,0 -4,5 L4,5 Q4.5,0 3.5,-5 Z" fill="#dc2626" stroke="#7f1d1d" strokeWidth="0.6" />
        <path d="M3.5,-3 Q8,-2 9,2" stroke="#fcd9b6" strokeWidth="2" strokeLinecap="round" fill="none" />
        <circle cx="9.5" cy="2.5" r="2.6" fill="#6b4423" stroke="#3f2a15" strokeWidth="0.6" />
        <path d="M-3.5,-3 Q-6,-1 -6,3" stroke="#fcd9b6" strokeWidth="2" strokeLinecap="round" fill="none" />
        <path d="M-1.5,5 Q-3,9 -2,13" stroke="#1e3a8a" strokeWidth="2.4" strokeLinecap="round" fill="none" />
        <path d="M1.5,5 Q4,9 5,12" stroke="#1e3a8a" strokeWidth="2.4" strokeLinecap="round" fill="none" />
      </g>
    </g>
  );
}

// Bat swing: tiny visual at home plate when the ball is hit
function BatSwing({ show }) {
  const [tick, setTick] = useState(1);
  useEffect(() => {
    if (!show) return;
    setTick(0);
    const start = performance.now();
    let raf;
    const loop = (now) => {
      const t = Math.min(1, (now - start) / 200);
      setTick(t);
      if (t < 1) raf = requestAnimationFrame(loop);
    };
    raf = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(raf);
  }, [show]);

  if (!show || tick >= 1) return null;
  // Bat rotates from -90° to +30° around home plate
  const angle = -90 + tick * 120;
  return (
    <g style={{ transform: `translate(200px, 330px) rotate(${angle}deg)`, transformOrigin: "200px 330px", pointerEvents: "none" }}>
      <rect x="200" y="324" width="34" height="6" rx="3" fill="#92400e" stroke="#451a03" strokeWidth="1" />
      <rect x="228" y="322" width="6" height="10" rx="2" fill="#fbbf24" />
    </g>
  );
}

// Legacy fallback (kept for places that may still ref it during transition)
function Ball({ x, y, animate, fast }) {
  return (
    <g style={{ transform: `translate(${x}px,${y}px)` }}>
      <circle r="9" fill="#fff" stroke="#cbd5e1" strokeWidth="1.5" />
      <path d="M-4 -5 Q-7 0 -4 5 M4 -5 Q7 0 4 5" stroke="#ef4444" strokeWidth="1.4" fill="none" />
    </g>
  );
}

// Pop-up calls don't need a "throw to pitcher" rehearse — they just hold the ball.
// Outfielder cover scenarios are also skipped — the outfielder was backing up,
// not handling the ball. Every other play ends with the ball needing to get back
// to the pitcher so the play stops.
const needsRehearseForSc = (s) => {
  if (!s) return false;
  if (s.noRehearse) return false;
  if (s.mode === "popup") return false;
  if (s.mode === "baserun") return false;
  if (s.correct === "P") return false;
  if (s.mode === "cover" && OUTFIELDERS.has(s.position)) return false;
  // MC scenarios for outfielders also skip
  if (s.mc && OUTFIELDERS.has(s.position)) return false;
  // PITCHER: the pitcher must be near the ball to stop the play. If the pitcher
  // threw the ball to a base (didn't keep it), remind them to go get it.
  // If the pitcher keeps it (covers a base themselves / holds it), no reminder.
  if (s.position === "P") {
    const correctArr = Array.isArray(s.correct) ? s.correct : [s.correct];
    return correctArr.length > 0 && correctArr.every((c) => BASES.includes(c));
  }
  return true;
};

// ============================================================
// MAIN APP
// ============================================================
export default function App() {
  const [screen, setScreen] = useState("home"); // home | difficulty | play | done | settings
  const [position, setPosition] = useState(null);
  const [difficulty, setDifficulty] = useState(null);
  const [queue, setQueue] = useState([]);
  const [idx, setIdx] = useState(0);
  const [phase, setPhase] = useState("ask"); // ask | move | reveal | rehearse | rehearseMove | done
  const [result, setResult] = useState(null);
  const [chosen, setChosen] = useState(null);
  const [attempts, setAttempts] = useState(0);
  const [stars, setStars] = useState(0);
  const [progress, setProgress] = useState({});
  // ----- Rewards -----
  const [totalStars, setTotalStars] = useState(0);   // lifetime first-try stars
  const [badges, setBadges] = useState({});          // { [position]: true } when mastered
  const [cleared, setCleared] = useState({});        // { [position-difficulty]: true }
  const [rewardPopup, setRewardPopup] = useState(null); // { type, title, sub, emoji } | null
  const rewardsLoaded = useRef(false);
  const [soundOn, setSoundOn] = useState(true);
  const [movePos, setMovePos] = useState({ x: 200, y: 200 }); // legacy, used by rehearse phase
  const [showHit, setShowHit] = useState(null); // legacy
  const [ballPath, setBallPath] = useState(null);
  const [puff, setPuff] = useState(null); // {x, y, key}
  const [pitcherRun, setPitcherRun] = useState(null); // {from, to, id} for running-pitcher animation
  const [batSwing, setBatSwing] = useState(0); // increment to retrigger
  const [availableVoices, setAvailableVoices] = useState([]);
  const [selectedVoiceName, setSelectedVoiceName] = useState(null);
  // Swipe-back review: when not null, we're viewing a previously answered
  // question read-only at this index. Null = live on the current question.
  const [reviewIdx, setReviewIdx] = useState(null);
  const touchStartX = useRef(null);

  // Generate unique path IDs so AnimatedBall restarts when path changes
  const pathIdRef = useRef(0);
  const nextPathId = () => ++pathIdRef.current;

  const needsRehearse = needsRehearseForSc;

  // ----- Persist rewards on-device (survives between sessions) -----
  // Works in two environments:
  //  • Claude app artifact   -> uses window.storage (async key/value API)
  //  • Web / Vercel deploy    -> falls back to localStorage
  const STORE_KEY = "ddiq-rewards";
  const loadRewards = async () => {
    try {
      if (typeof window !== "undefined" && window.storage && window.storage.get) {
        const res = await window.storage.get(STORE_KEY);
        if (res && res.value) return JSON.parse(res.value);
        return null;
      }
    } catch (e) { /* fall through to localStorage */ }
    try {
      if (typeof window !== "undefined" && window.localStorage) {
        const raw = window.localStorage.getItem(STORE_KEY);
        return raw ? JSON.parse(raw) : null;
      }
    } catch (e) { /* storage blocked (private mode etc.) */ }
    return null;
  };
  const saveRewards = async (data) => {
    const json = JSON.stringify(data);
    try {
      if (typeof window !== "undefined" && window.storage && window.storage.set) {
        await window.storage.set(STORE_KEY, json);
        return;
      }
    } catch (e) { /* fall through to localStorage */ }
    try {
      if (typeof window !== "undefined" && window.localStorage) {
        window.localStorage.setItem(STORE_KEY, json);
      }
    } catch (e) { /* storage unavailable — keep in-memory only */ }
  };

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const data = await loadRewards();
        if (!cancelled && data) {
          setTotalStars(data.totalStars || 0);
          setBadges(data.badges || {});
          setCleared(data.cleared || {});
          setProgress(data.progress || {});
        }
      } finally {
        rewardsLoaded.current = true;
      }
    })();
    return () => { cancelled = true; };
    // eslint-disable-next-line
  }, []);

  // Save whenever rewards change (after the initial load).
  useEffect(() => {
    if (!rewardsLoaded.current) return;
    saveRewards({ totalStars, badges, cleared, progress });
    // eslint-disable-next-line
  }, [totalStars, badges, cleared, progress]);

  const soundRef = useRef(soundOn); soundRef.current = soundOn;
  const audioRef = useRef(null);
  const voiceRef = useRef(null);
  const sc = queue[idx];

  // Pick the best-sounding voice once they load. Browsers load voices async,
  // so we listen for voiceschanged and cache the chosen one.
  useEffect(() => {
    const s = window.speechSynthesis;
    if (!s) return;

    // Preference order: smooth, natural, child-friendly voices first.
    const PREFERRED = [
      "Google US English",
      "Microsoft Aria Online (Natural) - English (United States)",
      "Microsoft Jenny Online (Natural) - English (United States)",
      "Microsoft Ava Online (Natural) - English (United States)",
      "Microsoft Emma Online (Natural) - English (United States)",
      "Samantha", "Karen", "Moira", "Tessa",
      "Microsoft Zira - English (United States)",
      "Microsoft Aria", "Microsoft Jenny",
    ];

    // Restore saved selection if any
    let saved = null;
    try { saved = localStorage.getItem("ddiq-voice"); } catch (e) {}

    const pickVoice = () => {
      const voices = s.getVoices();
      if (!voices.length) return;

      // Filter to English voices that aren't obviously low-quality
      const englishVoices = voices.filter(
        (v) => /^en[-_]/i.test(v.lang) && !/espeak/i.test(v.name)
      );
      setAvailableVoices(englishVoices.length ? englishVoices : voices);

      // Honor saved voice if it still exists
      if (saved) {
        const match = voices.find((v) => v.name === saved);
        if (match) { voiceRef.current = match; setSelectedVoiceName(match.name); return; }
      }

      // Otherwise pick the best by preference
      for (const name of PREFERRED) {
        const v = voices.find((v) => v.name === name);
        if (v) { voiceRef.current = v; setSelectedVoiceName(v.name); return; }
      }
      const femaleHints = /samantha|karen|moira|tessa|aria|jenny|emma|ava|zira|female/i;
      const pick =
        englishVoices.find((v) => femaleHints.test(v.name)) ||
        englishVoices.find((v) => v.localService === false) ||
        englishVoices[0] ||
        voices[0];
      voiceRef.current = pick || null;
      if (pick) setSelectedVoiceName(pick.name);
    };

    pickVoice();
    s.addEventListener("voiceschanged", pickVoice);
    return () => s.removeEventListener("voiceschanged", pickVoice);
  }, []);

  // Choose a specific voice by name (from settings screen)
  const chooseVoice = (name) => {
    const v = availableVoices.find((x) => x.name === name);
    if (!v) return;
    voiceRef.current = v;
    setSelectedVoiceName(name);
    try { localStorage.setItem("ddiq-voice", name); } catch (e) {}
    // Preview
    try {
      const s = window.speechSynthesis;
      s.cancel();
      const u = new SpeechSynthesisUtterance("Hi there, Dragons! Ready to play some baseball?");
      u.voice = v; u.lang = v.lang || "en-US";
      u.rate = 0.95; u.pitch = 1.05; u.volume = 1;
      s.speak(u);
    } catch (e) {}
  };

  // ---- AUDIO ----
  const getCtx = () => {
    if (!audioRef.current) {
      try { audioRef.current = new (window.AudioContext || window.webkitAudioContext)(); }
      catch (e) { audioRef.current = null; }
    }
    return audioRef.current;
  };
  const tone = (freq, start, dur, type = "triangle", gain = 0.14) => {
    if (!soundRef.current) return;
    const ctx = getCtx(); if (!ctx) return;
    try {
      const o = ctx.createOscillator(); const g = ctx.createGain();
      o.type = type; o.frequency.value = freq; o.connect(g); g.connect(ctx.destination);
      const t = ctx.currentTime + start;
      g.gain.setValueAtTime(gain, t);
      g.gain.exponentialRampToValueAtTime(0.0001, t + dur);
      o.start(t); o.stop(t + dur + 0.03);
    } catch (e) {}
  };
  const sfxCorrect = () => { tone(523, 0, 0.12); tone(659, 0.1, 0.12); tone(784, 0.2, 0.22); };
  const sfxWrong = () => { tone(300, 0, 0.16, "sine", 0.1); tone(225, 0.13, 0.22, "sine", 0.1); };
  const sfxCheer = () => { [523, 587, 659, 784, 880, 1047].forEach((f, i) => tone(f, i * 0.09, 0.18)); };

  // Original cheerful home-screen jingle — a bouncy little major-key tune.
  // Built from our own notes (no copyrighted melody). Plays once on home mount.
  const playJingle = () => {
    if (!soundRef.current) return;
    // Notes: C E G C(hi) — G E G — bouncy turnaround — big finish
    const mel = [
      [523, 0.00, 0.16], [659, 0.16, 0.16], [784, 0.32, 0.16], [1047, 0.48, 0.22],
      [784, 0.74, 0.14], [659, 0.90, 0.14], [784, 1.04, 0.20],
      [880, 1.30, 0.14], [988, 1.46, 0.14], [1047, 1.62, 0.30],
      [1319, 1.96, 0.34],
    ];
    mel.forEach(([f, t, d]) => tone(f, t, d, "triangle", 0.12));
    // Soft bass plucks underneath for a fuller, game-y feel
    const bass = [[131, 0.00, 0.3], [196, 0.74, 0.3], [165, 1.30, 0.3], [131, 1.96, 0.5]];
    bass.forEach(([f, t, d]) => tone(f, t, d, "sine", 0.10));
  };
  const sfxClick = () => tone(440, 0, 0.06, "square", 0.08);
  // Crack of the bat — short, sharp, woody
  const sfxCrack = () => {
    tone(180, 0, 0.04, "square", 0.18);
    tone(90, 0, 0.06, "sawtooth", 0.16);
    tone(450, 0.01, 0.05, "triangle", 0.12);
  };
  // Glove pop — soft "thud" when ball lands
  const sfxPop = () => {
    tone(220, 0, 0.05, "sine", 0.16);
    tone(140, 0.01, 0.08, "sine", 0.14);
  };
  // OUT! callout chord
  const sfxOut = () => {
    tone(659, 0, 0.18, "triangle", 0.16);
    tone(880, 0.05, 0.22, "triangle", 0.16);
    tone(1175, 0.12, 0.30, "triangle", 0.16);
  };

  const speak = (text) => {
    if (!soundRef.current) return;
    try {
      const s = window.speechSynthesis; if (!s) return;
      s.cancel();
      const u = new SpeechSynthesisUtterance(expandPositions(text));
      if (voiceRef.current) {
        u.voice = voiceRef.current;
        u.lang = voiceRef.current.lang || "en-US";
      } else {
        u.lang = "en-US";
      }
      // Tuned for kids: slightly slower than normal, natural pitch, full volume
      u.rate = 0.95;
      u.pitch = 1.05;
      u.volume = 1;
      s.speak(u);
    } catch (e) {}
  };
  const stopSpeak = () => { try { window.speechSynthesis && window.speechSynthesis.cancel(); } catch (e) {} };

  // Estimate how long it takes to speak a string (ms), so we don't cut off the
  // explanation before switching to the "give it to the pitcher" step.
  // ~13 chars/sec at our rate, clamped to a sensible range. +1000ms pause after.
  const estimateSpeechMs = (text) => {
    if (!text) return 1500;
    const chars = expandPositions(text).length;
    const ms = Math.round((chars / 13) * 1000);
    return Math.min(9000, Math.max(2200, ms));
  };
  const rehearseDelay = (sc) => estimateSpeechMs(`Yes! ${sc.why}`) + 500;

  // ---- SCENARIO LIFECYCLE ----
  useEffect(() => {
    if (screen !== "play" || !sc) return;
    setPhase("ask"); setResult(null); setChosen(null); setAttempts(0);
    setPuff(null); setPitcherRun(null);

    // Animate a HIT from home plate to wherever the ball is going
    if (sc.mode === "throw" || sc.mode === "field") {
      const target = displayedPos(sc.ballAt, sc) || POS[sc.ballAt];
      const fromBatter = { x: 215, y: 318 }; // a touch off home plate
      setBatSwing((n) => n + 1); // trigger swing
      setTimeout(() => {
        sfxCrack();
        const type = sc.variant === "hard" ? "rocket" : "hit";
        setBallPath({ from: fromBatter, to: target, type, id: nextPathId(),
          arrivePos: target });
      }, 90);
      const landDelay = sc.variant === "hard" ? 410 : 870;
      setTimeout(() => { sfxPop(); setPuff({ x: target.x, y: target.y, key: Date.now() }); }, landDelay);
      const speakDelay = sc.variant === "hard" ? 470 : 920;
      setTimeout(() => speak(sc.prompt), speakDelay);
    } else if (sc.mode === "cover") {
      const target = displayedPos(sc.ballAt, sc) || POS[sc.ballAt];
      const fromBatter = { x: 215, y: 318 };
      setBatSwing((n) => n + 1);
      setTimeout(() => {
        sfxCrack();
        const type = sc.variant === "hard" ? "rocket" : "hit";
        setBallPath({ from: fromBatter, to: target, type, id: nextPathId(),
          arrivePos: target });
      }, 90);
      setTimeout(() => { sfxPop(); setPuff({ x: target.x, y: target.y, key: Date.now() }); }, 870);
      setTimeout(() => speak(sc.prompt), 920);
    } else if (sc.mode === "popup") {
      setBallPath(null);
      setTimeout(() => speak(sc.prompt), 250);
    } else if (sc.mode === "baserun") {
      // Base running: no hit/ball flight. Just show the runner and ask.
      setBallPath(null);
      setTimeout(() => speak(sc.prompt), 250);
    }
  // eslint-disable-next-line
  }, [screen, idx, queue]);

  // ---- CHOICE HANDLER ----
  const choose = (key) => {
    if (phase !== "ask" && phase !== "rehearse") return;
    sfxClick();

    // REHEARSE phase
    if (phase === "rehearse") {
      const correctKey = Array.isArray(sc.correct) ? sc.correct[0] : sc.correct;
      const ballPos = displayedPos(correctKey, sc) || POS[correctKey] || POS[sc.ballAt] || POS["P"];

      // PITCHER module: tap the BALL → pitcher runs over and catches it.
      if (sc.position === "P") {
        if (key !== "BALL") {
          sfxWrong();
          speak("Tap the ball! The pitcher needs to go get it.");
          return;
        }
        setPhase("rehearseMove");
        // Run the pitcher figure from the mound to the ball
        setPitcherRun({ from: POS["P"], to: ballPos, id: nextPathId() });
        setTimeout(() => {
          sfxPop();
          setPuff({ x: ballPos.x, y: ballPos.y, key: Date.now() });
          sfxCorrect();
          speak("Yes! The pitcher got the ball — play stops!");
          setPhase("done");
        }, 700);
        return;
      }

      // Other positions: tap the PITCHER → ball flies back to the mound.
      setPhase("rehearseMove");
      setBallPath({ from: ballPos, to: POS["P"], type: "throw", id: nextPathId(),
        arrivePos: POS["P"] });
      setTimeout(() => {
        setPuff({ x: POS["P"].x, y: POS["P"].y, key: Date.now() });
        if (key === "P") {
          sfxCorrect();
          speak("Yes! Pitcher has the ball — play stops!");
        } else {
          sfxWrong();
          speak("The pitcher needs the ball to stop the play. Tap the pitcher!");
        }
        setPhase("done");
      }, 540);
      return;
    }

    setChosen(key);
    setPhase("move");

    // MC mode: kid tapped a multiple-choice button (key is a number index).
    // No ball animation — the answer is conceptual. Just evaluate and reveal.
    if (sc.mc && typeof key === "number") {
      const isCorrect = sc.mc[key]?.correct;
      const firstTryMC = attempts === 0;
      // Short delay so the button press feels responsive
      setTimeout(() => {
        if (isCorrect) {
          if (firstTryMC) setStars((s) => s + 1);
          sfxOut();
          speak(`Yes! ${sc.why}`);
          setResult("correct");
          // Outfielder cover scenarios skip rehearse (already handled by needsRehearseForSc)
          if (needsRehearseForSc(sc)) {
            setPhase("reveal");
            setTimeout(() => {
              if (sc.position === "P") setBallPath(null); // ball shown as tappable target instead
              setPhase("rehearse");
              speak(sc.position === "P" ? "Now tap the ball — the pitcher will run over and get it!" : "Now tap the pitcher to stop the play!");
            }, rehearseDelay(sc));
          } else {
            setPhase("done");
          }
        } else {
          setAttempts((a) => a + 1);
          sfxWrong();
          speak(`Not quite. ${sc.hint}`);
          setResult("wrong");
          setPhase("reveal");
        }
      }, 200);
      return;
    }

    // Animate the ball from the fielder to the chosen target (a base or another fielder)
    const dest = displayedPos(key, sc) || POS[key];
    if (dest && sc.mode !== "popup") {
      const fromPos = displayedPos(sc.ballAt, sc) || POS[sc.ballAt] || { x: 200, y: 200 };
      const type = sc.variant === "hard" ? "rocket" : "throw";
      setBallPath({ from: fromPos, to: dest, type, id: nextPathId(), arrivePos: dest });
    }

    // Allow multi-correct answers if sc.correct is an array
    const isCorrectKey = (k) =>
      Array.isArray(sc.correct) ? sc.correct.includes(k) : k === sc.correct;

    const firstTry = attempts === 0;
    setTimeout(() => {
      if (dest && sc.mode !== "popup") {
        sfxPop();
        setPuff({ x: dest.x, y: dest.y, key: Date.now() });
      }
      if (isCorrectKey(key)) {
        if (firstTry) setStars((s) => s + 1);
        sfxOut();
        speak(`Yes! ${sc.why}`);
        setResult("correct");

        if (needsRehearse(sc)) {
          setPhase("reveal");
          setTimeout(() => {
            if (sc.position === "P") setBallPath(null); // ball shown as tappable target instead
            setPhase("rehearse");
            speak(sc.position === "P" ? "Now tap the ball — the pitcher will run over and get it!" : "Now tap the pitcher to stop the play!");
          }, rehearseDelay(sc));
        } else {
          setPhase("done");
        }
      } else {
        setAttempts((a) => a + 1);
        sfxWrong();
        speak(`Not quite. ${sc.hint}`);
        setResult("wrong");
        setPhase("reveal");
      }
    }, 560);
  };

  const tryAgain = () => {
    sfxClick();
    setResult(null); setChosen(null); setPhase("ask");
    setPuff(null);
    if (sc.mode !== "popup") {
      // Re-animate the hit
      const target = POS[sc.ballAt];
      const fromBatter = { x: 215, y: 318 };
      setBatSwing((n) => n + 1);
      setTimeout(() => {
        const type = sc.variant === "hard" ? "rocket" : "hit";
        setBallPath({ from: fromBatter, to: target, type, id: nextPathId(), arrivePos: target });
      }, 90);
    }
    setTimeout(() => speak(sc.prompt), 100);
  };

  const next = () => {
    sfxClick();
    if (idx + 1 < queue.length) {
      setIdx((i) => i + 1);
    } else {
      stopSpeak();
      const total = queue.length;
      const key = `${position}-${difficulty}`;
      setProgress((p) => ({ ...p, [key]: Math.max(p[key] || 0, stars) }));

      // ----- Award rewards -----
      const prevTotal = totalStars;
      const newTotal = prevTotal + stars;
      setTotalStars(newTotal);

      const rewards = []; // queued celebrations

      // Rank-up?
      const prevRank = rankForStars(prevTotal);
      const newRank = rankForStars(newTotal);
      if (newRank.name !== prevRank.name) {
        rewards.push({ type: "rank", emoji: newRank.emoji,
          title: `New Rank: ${newRank.name}!`, sub: `You've earned ${newTotal} stars.` });
      }

      // Difficulty cleared?
      if (stars >= clearThreshold(difficulty) && !cleared[key]) {
        setCleared((c) => ({ ...c, [key]: true }));
      }

      // Position mastered? (Hard with a strong score) -> badge
      if (difficulty === "hard" && stars >= MASTER_THRESHOLD && !badges[position]) {
        setBadges((b) => ({ ...b, [position]: true }));
        rewards.push({ type: "badge", emoji: (POS_META[position].img ? "🏅" : POS_META[position].emoji),
          title: `${POS_META[position].name} Badge earned!`, sub: "You mastered this position!" });
      }

      // Show the first celebration (if any) after the cheer.
      if (rewards.length > 0) setRewardPopup(rewards[0]);

      setTimeout(sfxCheer, 200);
      setScreen("done");
    }
  };

  const goHome = () => { stopSpeak(); setRewardPopup(null); setPosition(null); setDifficulty(null); setScreen("home"); setTimeout(() => playJingle(), 250); };
  const goBack = () => { stopSpeak(); setRewardPopup(null); setDifficulty(null); setScreen("difficulty"); };

  // ---- Swipe-back review navigation ----
  // Step back to review a previously answered question (read-only).
  const reviewPrev = () => {
    stopSpeak();
    const cur = reviewIdx === null ? idx : reviewIdx;
    if (cur > 0) { sfxClick(); setReviewIdx(cur - 1); }
  };
  // Step forward through review; returning past the last reviewed = back to live.
  const reviewNext = () => {
    if (reviewIdx === null) return;
    stopSpeak();
    if (reviewIdx + 1 >= idx) { sfxClick(); setReviewIdx(null); } // back to live question
    else { sfxClick(); setReviewIdx(reviewIdx + 1); }
  };
  const exitReview = () => { stopSpeak(); setReviewIdx(null); };

  const onTouchStart = (e) => { touchStartX.current = e.touches[0].clientX; };
  const onTouchEnd = (e) => {
    if (touchStartX.current == null) return;
    const dx = e.changedTouches[0].clientX - touchStartX.current;
    touchStartX.current = null;
    if (Math.abs(dx) < 60) return; // ignore small swipes
    if (dx > 0) reviewPrev();   // swipe right → go back
    else reviewNext();          // swipe left → go forward / return to live
  };

  const pickPosition = (p) => {
    sfxClick();
    setPosition(p);
    if (p === "POPUP") {
      setScreen("difficulty"); // popup also has difficulty
    } else {
      setScreen("difficulty");
    }
  };
  const pickDifficulty = (d) => {
    sfxClick();
    setDifficulty(d);
    const all = SCENARIOS[position] || [];

    // Classify each scenario by how many runners are on base.
    const ONE = new Set(["r1", "r2", "r3"]);
    const MULTI = new Set(["r12", "r13", "r23", "loaded"]);
    const cat = (s) => {
      const b = s.baseSit;
      if (b === "empty") return "empty";
      if (ONE.has(b)) return "one";
      if (MULTI.has(b)) return "multi";
      return "other"; // popups / base-running with no baseSit
    };

    const shuffle = (arr) => [...arr].sort(() => Math.random() - 0.5);

    // Easy = 4 questions (bases empty), Medium = 7 (one runner), Hard = 10 (multiple runners).
    // Each tier shows the most common plays for that base situation. If a tier is short
    // on scenarios, we top up from the next-closest situation so the count is always met.
    const PLAN = { easy: { n: 4, order: ["empty", "one", "multi", "other"] },
                   medium: { n: 7, order: ["one", "empty", "multi", "other"] },
                   hard: { n: 10, order: ["multi", "one", "empty", "other"] } };
    const plan = PLAN[d] || PLAN.easy;

    let picked;
    if (position === "POPUP" || position === "RUNNER") {
      // These modules aren't about base runners — keep the difficulty-tagged sets,
      // just capped to the new question counts.
      picked = shuffle(all.filter((s) => s.difficulty === d)).slice(0, plan.n);
    } else {
      const byCat = { empty: [], one: [], multi: [], other: [] };
      all.forEach((s) => byCat[cat(s)].push(s));
      Object.keys(byCat).forEach((k) => { byCat[k] = shuffle(byCat[k]); });
      picked = [];
      for (const c of plan.order) {
        for (const s of byCat[c]) {
          if (picked.length >= plan.n) break;
          picked.push(s);
        }
        if (picked.length >= plan.n) break;
      }
    }

    const q = picked.map((s) => {
      const mc = generateMCOptions(s);
      return mc ? { ...s, mc } : s;
    });
    setQueue(q); setIdx(0); setStars(0);
    setReviewIdx(null);
    setRewardPopup(null);
    setScreen("play");
  };

  // ============================================================
  // SCREENS
  // ============================================================
  const page = {
    fontFamily: "'Fredoka', system-ui, sans-serif",
    minHeight: "100vh",
    background: "radial-gradient(circle at 50% -10%, #bae6fd 0%, #7dd3fc 38%, #38bdf8 100%)",
    padding: "12px 12px 40px",
    boxSizing: "border-box", color: "#0f2747",
  };
  const card = {
    background: "rgba(255,255,255,0.97)", borderRadius: 24,
    boxShadow: "0 18px 40px rgba(13,71,161,0.28)",
    maxWidth: 480, margin: "0 auto", overflow: "hidden",
  };
  const bigBtn = (bg, sh) => ({
    background: bg, color: "#fff", border: "none",
    fontFamily: "inherit", fontWeight: 700, fontSize: 18,
    padding: "13px 22px", borderRadius: 16, cursor: "pointer",
    boxShadow: `0 5px 0 ${sh}`, transition: "transform .08s, box-shadow .08s",
    WebkitTapHighlightColor: "transparent",
  });

  // ---- HOME: pick position ----
  // ---- TROPHY CASE ----
  if (screen === "trophies") {
    const rank = rankForStars(totalStars);
    const nr = nextRankFor(totalStars);
    const playablePositions = ["P","C","1B","2B","SS","3B","LF","CF","RF"];
    const progressToNext = nr
      ? Math.min(100, Math.round(((totalStars - rank.min) / (nr.min - rank.min)) * 100))
      : 100;
    return (
      <div style={page}>
        <style>{styleSheet}</style>
        <div style={{ ...card, padding: "20px 18px 24px" }}>
          <button className="press" onClick={() => { sfxClick(); setScreen("home"); }}
            style={{ ...bigBtn("#e2e8f0", "#94a3b8"), color: "#475569", fontSize: 14, padding: "7px 12px", marginBottom: 14 }}>
            ← Back
          </button>
          <h1 style={{ textAlign: "center", margin: "0 0 4px", fontSize: 26, fontWeight: 800, color: "#1e3a8a" }}>
            🏆 Trophy Case
          </h1>

          {/* Rank card */}
          <div style={{ background: "linear-gradient(135deg,#1e3a8a,#2563eb)", borderRadius: 18,
            padding: "16px", textAlign: "center", margin: "12px 0", boxShadow: "0 4px 0 #15296b" }}>
            <div style={{ fontSize: 44, lineHeight: 1 }}>{rank.emoji}</div>
            <div style={{ fontSize: 22, fontWeight: 800, color: "#fff", marginTop: 4 }}>{rank.name}</div>
            <div style={{ fontSize: 14, color: "#bfdbfe", fontWeight: 600, marginTop: 2 }}>⭐ {totalStars} total stars</div>
            {/* Progress bar to next rank */}
            <div style={{ background: "rgba(255,255,255,0.25)", borderRadius: 8, height: 12, marginTop: 10, overflow: "hidden" }}>
              <div style={{ width: `${progressToNext}%`, height: "100%", background: "#fbbf24", borderRadius: 8, transition: "width .5s" }} />
            </div>
            <div style={{ fontSize: 12, color: "#dbeafe", marginTop: 5, fontWeight: 600 }}>
              {nr ? `${nr.min - totalStars} stars to ${nr.emoji} ${nr.name}` : "Top rank reached — Hall of Famer!"}
            </div>
          </div>

          {/* Badges */}
          <h2 style={{ fontSize: 16, fontWeight: 800, color: "#0f2747", margin: "8px 0 8px" }}>
            🏅 Position Badges ({Object.keys(badges).filter(p => playablePositions.includes(p)).length}/9)
          </h2>
          <p style={{ fontSize: 12.5, color: "#64748b", margin: "0 0 10px", fontWeight: 500 }}>
            Master a position by scoring {MASTER_THRESHOLD}+ on Hard to earn its badge!
          </p>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}>
            {playablePositions.map((p) => {
              const meta = POS_META[p];
              const earned = !!badges[p];
              return (
                <div key={p} style={{ textAlign: "center", background: earned ? "#fffbeb" : "#f1f5f9",
                  border: `2px solid ${earned ? "#f59e0b" : "#cbd5e1"}`, borderRadius: 14, padding: "9px 4px",
                  opacity: earned ? 1 : 0.7, position: "relative" }}>
                  {meta.img
                    ? <img src={meta.img} alt={meta.name} width={40} height={40}
                        style={{ display: "block", margin: "0 auto", objectFit: "contain",
                          filter: earned ? "none" : "grayscale(100%)" }} />
                    : <div style={{ fontSize: 26 }}>{meta.emoji}</div>}
                  <div style={{ fontSize: 11, fontWeight: 700, color: earned ? meta.color : "#94a3b8", marginTop: 3, lineHeight: 1.1 }}>
                    {meta.name}
                  </div>
                  <div style={{ fontSize: 13, marginTop: 1 }}>{earned ? "🏅" : "🔒"}</div>
                </div>
              );
            })}
          </div>

          <p style={{ textAlign: "center", fontSize: 12, color: "#94a3b8", margin: "18px 0 0" }}>
            Keep playing to climb the ranks! ⚾
          </p>
        </div>
      </div>
    );
  }

  // ---- HOME ----
  if (screen === "home") {
    return (
      <div style={page}>
        <style>{styleSheet}</style>
        <div style={{ ...card, padding: "22px 18px 24px", position: "relative" }}>
          <button onClick={() => { sfxClick(); setScreen("settings"); }} className="press"
            style={{ position: "absolute", top: 14, right: 14, background: "#fff",
              border: "2px solid #94a3b8", borderRadius: 12, padding: "6px 10px",
              fontSize: 18, cursor: "pointer", fontFamily: "inherit", lineHeight: 1,
              boxShadow: "0 3px 0 #94a3b8" }}>⚙️</button>
          <button onClick={() => { playJingle(); }} className="press"
            style={{ position: "absolute", top: 14, left: 14, background: "#fff",
              border: "2px solid #f59e0b", borderRadius: 12, padding: "6px 10px",
              fontSize: 18, cursor: "pointer", fontFamily: "inherit", lineHeight: 1,
              boxShadow: "0 3px 0 #f59e0b" }}>🎵</button>
          <div style={{ display: "flex", justifyContent: "center", animation: "float 3s ease-in-out infinite" }}>
            <DragonCoach size={90} />
          </div>
          <h1 style={{ textAlign: "center", margin: "8px 0 2px", fontSize: 30, fontWeight: 700, color: "#1e3a8a", letterSpacing: -0.5 }}>
            Baseball IQ
          </h1>
          <p style={{ textAlign: "center", margin: "0 0 16px", fontSize: 15, color: "#475569", fontWeight: 500 }}>
            Pick your position. Coach Bruce will quiz you on what to do!

          </p>
          {/* Rewards banner — tap to open the Trophy Case */}
          {(() => {
            const rank = rankForStars(totalStars);
            const nr = nextRankFor(totalStars);
            const badgeCount = Object.keys(badges).length;
            return (
              <button onClick={() => { sfxClick(); setScreen("trophies"); }} className="press"
                style={{ display: "flex", alignItems: "center", gap: 10, width: "100%",
                  background: "linear-gradient(135deg,#1e3a8a,#2563eb)", border: "none",
                  borderRadius: 16, padding: "10px 14px", marginBottom: 14, cursor: "pointer",
                  fontFamily: "inherit", boxShadow: "0 4px 0 #15296b", textAlign: "left" }}>
                <div style={{ fontSize: 30, lineHeight: 1 }}>{rank.emoji}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 15, fontWeight: 800, color: "#fff" }}>{rank.name}</div>
                  <div style={{ fontSize: 12, color: "#bfdbfe", fontWeight: 600 }}>
                    ⭐ {totalStars} stars · 🏅 {badgeCount}/9 badges
                    {nr ? ` · ${nr.min - totalStars} to ${nr.name}` : " · MAXED OUT!"}
                  </div>
                </div>
                <div style={{ fontSize: 22 }}>🏆</div>
              </button>
            );
          })()}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 9 }}>
            {POSITION_ORDER.map((p) => {
              const meta = POS_META[p];
              return (
                <button key={p} onClick={() => pickPosition(p)} className="press"
                  style={{ background: "#fff", border: `3px solid ${meta.color}`,
                    borderRadius: 16, padding: "10px 8px", cursor: "pointer",
                    fontFamily: "inherit", boxShadow: `0 4px 0 ${meta.color}`,
                    textAlign: "center" }}>
                  {meta.img
                    ? <img src={meta.img} alt={meta.name} width={46} height={46}
                        style={{ display: "block", margin: "0 auto", objectFit: "contain" }} />
                    : <div style={{ fontSize: 28, lineHeight: 1 }}>{meta.emoji}</div>}
                  <div style={{ fontSize: 14, fontWeight: 700, color: meta.color, marginTop: 4, lineHeight: 1.15 }}>{meta.name}</div>
                </button>
              );
            })}
          </div>
          <p style={{ textAlign: "center", fontSize: 12, color: "#94a3b8", margin: "14px 0 0" }}>
            For Mira Mesa Little Stars Blue · Built by Coach Mike 🐉
          </p>
        </div>
      </div>
    );
  }

  // ---- SETTINGS ----
  if (screen === "settings") {
    return (
      <div style={page}>
        <style>{styleSheet}</style>
        <div style={{ ...card, padding: "20px 18px 24px" }}>
          <button onClick={() => { sfxClick(); stopSpeak(); setScreen("home"); }} className="press"
            style={{ ...bigBtn("#e2e8f0", "#94a3b8"), color: "#475569", fontSize: 14, padding: "7px 12px", marginBottom: 14 }}>
            ← Back
          </button>
          <h2 style={{ margin: "0 0 4px", fontSize: 24, fontWeight: 700, color: "#1e3a8a", textAlign: "center" }}>
            ⚙️ Settings
          </h2>
          <p style={{ textAlign: "center", margin: "0 0 18px", fontSize: 14, color: "#64748b" }}>
            Pick Coach Bruce's voice. Tap to hear a preview.
          </p>

          {availableVoices.length === 0 ? (
            <div style={{ background: "#fef3c7", border: "2px solid #f59e0b",
              borderRadius: 12, padding: "12px", color: "#92400e", fontSize: 14, fontWeight: 500 }}>
              Loading voices… If none appear, your device may not have voices installed.
              Try a different browser (Chrome, Safari) or check your phone's text-to-speech settings.
            </div>
          ) : (
            <div style={{ maxHeight: 380, overflowY: "auto", paddingRight: 4 }}>
              {availableVoices.map((v) => {
                const isSelected = v.name === selectedVoiceName;
                const isNatural = /natural|online/i.test(v.name) || v.localService === false;
                return (
                  <button key={v.name} onClick={() => chooseVoice(v.name)} className="press"
                    style={{ display: "flex", alignItems: "center", gap: 10, width: "100%",
                      textAlign: "left", background: isSelected ? "#dcfce7" : "#fff",
                      border: `3px solid ${isSelected ? "#22c55e" : "#cbd5e1"}`,
                      borderRadius: 14, padding: "11px 13px", marginBottom: 8,
                      cursor: "pointer", fontFamily: "inherit",
                      boxShadow: isSelected ? "0 4px 0 #16a34a" : "0 3px 0 #cbd5e1" }}>
                    <div style={{ fontSize: 22, width: 30, textAlign: "center" }}>
                      {isSelected ? "✅" : "🔊"}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 15, fontWeight: 700, color: isSelected ? "#166534" : "#0f2747", lineHeight: 1.2 }}>
                        {v.name}
                        {isNatural && (
                          <span style={{ marginLeft: 6, fontSize: 11, fontWeight: 700,
                            background: "#dbeafe", color: "#1e40af", padding: "1px 6px", borderRadius: 6 }}>
                            ✨ Natural
                          </span>
                        )}
                      </div>
                      <div style={{ fontSize: 12, color: "#64748b", marginTop: 2 }}>
                        {v.lang} {v.localService ? "· Offline" : "· Online"}
                      </div>
                    </div>
                  </button>
                );
              })}
            </div>
          )}

          <p style={{ textAlign: "center", fontSize: 11, color: "#94a3b8", margin: "14px 0 0" }}>
            Your selection is saved for next time.
          </p>
        </div>
      </div>
    );
  }

  // ---- DIFFICULTY ----
  if (screen === "difficulty") {
    const meta = POS_META[position];
    return (
      <div style={page}>
        <style>{styleSheet}</style>
        <div style={{ ...card, padding: "22px 20px 24px" }}>
          <button onClick={goHome} className="press"
            style={{ ...bigBtn("#e2e8f0", "#94a3b8"), color: "#475569", fontSize: 14, padding: "7px 12px", marginBottom: 14 }}>
            ← Back
          </button>
          <div style={{ textAlign: "center" }}>
            {meta.img
              ? <img src={meta.img} alt={meta.name} width={84} height={84}
                  style={{ display: "block", margin: "0 auto", objectFit: "contain" }} />
              : <div style={{ fontSize: 52 }}>{meta.emoji}</div>}
            <h2 style={{ margin: "4px 0 4px", fontSize: 26, fontWeight: 700, color: meta.color }}>{meta.name}</h2>
            <p style={{ margin: "0 0 20px", fontSize: 14, color: "#475569" }}>{meta.blurb}</p>
          </div>
          {[
            { d: "easy", label: "🟢 Easy", desc: "Bases empty · 4 plays" },
            { d: "medium", label: "🟡 Medium", desc: "One runner on · 7 plays" },
            { d: "hard", label: "🔴 Hard", desc: "Multiple runners · 10 plays" },
          ].map((x) => {
            const has = (SCENARIOS[position] || []).some((s) => s.difficulty === x.d);
            const best = progress[`${position}-${x.d}`];
            return (
              <button key={x.d} onClick={() => has && pickDifficulty(x.d)} disabled={!has} className="press"
                style={{ display: "flex", alignItems: "center", gap: 12, width: "100%", textAlign: "left",
                  background: has ? "#fff" : "#f1f5f9", border: `3px solid ${has ? meta.color : "#cbd5e1"}`,
                  borderRadius: 16, padding: "13px 14px", marginBottom: 10, opacity: has ? 1 : 0.55,
                  cursor: has ? "pointer" : "not-allowed", fontFamily: "inherit",
                  boxShadow: has ? `0 4px 0 ${meta.color}` : "none" }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 18, fontWeight: 700, color: has ? meta.color : "#94a3b8" }}>{x.label}</div>
                  <div style={{ fontSize: 13, color: "#64748b", fontWeight: 500 }}>{x.desc}</div>
                </div>
                <div style={{ fontSize: 14, fontWeight: 700, color: "#f59e0b" }}>
                  {best != null ? "⭐".repeat(Math.max(1, Math.min(3, Math.ceil(best/2)))) : has ? "▶" : ""}
                </div>
              </button>
            );
          })}
        </div>
      </div>
    );
  }

  // ---- DONE ----
  if (screen === "done") {
    const meta = POS_META[position];
    const total = queue.length;
    const great = stars >= Math.max(1, total - 1);
    const rank = rankForStars(totalStars);
    return (
      <div style={page}>
        <style>{styleSheet}</style>
        {/* Reward celebration popup */}
        {rewardPopup && (
          <div onClick={() => setRewardPopup(null)}
            style={{ position: "fixed", inset: 0, background: "rgba(15,23,42,0.72)", zIndex: 50,
              display: "flex", alignItems: "center", justifyContent: "center", padding: 24 }}>
            <div style={{ background: "#fff", borderRadius: 22, padding: "26px 22px", maxWidth: 320,
              textAlign: "center", animation: "pop 0.5s ease", boxShadow: "0 12px 40px rgba(0,0,0,0.4)" }}>
              <div style={{ fontSize: 64, lineHeight: 1, animation: "float 2s ease-in-out infinite" }}>{rewardPopup.emoji}</div>
              <div style={{ fontSize: 13, fontWeight: 800, color: "#f59e0b", letterSpacing: 1, marginTop: 8 }}>
                {rewardPopup.type === "rank" ? "RANK UP!" : "BADGE UNLOCKED!"}
              </div>
              <h2 style={{ fontSize: 22, fontWeight: 800, color: "#1e3a8a", margin: "4px 0 4px" }}>{rewardPopup.title}</h2>
              <p style={{ fontSize: 14, color: "#475569", fontWeight: 500, margin: "0 0 16px" }}>{rewardPopup.sub}</p>
              <button className="press" onClick={() => setRewardPopup(null)}
                style={{ ...bigBtn("#f59e0b", "#b45309"), width: "100%" }}>
                Awesome! 🎉
              </button>
            </div>
          </div>
        )}
        <div style={{ ...card, padding: "26px 22px", textAlign: "center" }}>
          <div style={{ animation: "pop 0.5s ease" }}><DragonCoach size={108} mood="cheer" /></div>
          <h1 style={{ fontSize: 28, fontWeight: 700, color: meta.color, margin: "8px 0 4px" }}>
            {great ? "All-Star!" : "Nice Work!"}
          </h1>
          <p style={{ fontSize: 16, color: "#475569", fontWeight: 500, margin: "0 0 12px" }}>
            You finished <b>{meta.name}</b> · {difficulty}
          </p>
          <div style={{ fontSize: 28, letterSpacing: 4, margin: "4px 0 6px" }}>
            {"⭐".repeat(stars)}{"▫️".repeat(Math.max(0, total - stars))}
          </div>
          <p style={{ fontSize: 15, color: "#0f2747", fontWeight: 600, margin: "0 0 12px" }}>
            {stars} of {total} on the first try!
          </p>
          {/* Lifetime rewards strip */}
          <div onClick={() => { sfxClick(); setScreen("trophies"); }}
            style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
              background: "#eff6ff", border: "2px solid #bfdbfe", borderRadius: 14,
              padding: "8px 12px", margin: "0 0 18px", cursor: "pointer" }}>
            <span style={{ fontSize: 20 }}>{rank.emoji}</span>
            <span style={{ fontSize: 13, fontWeight: 700, color: "#1e3a8a" }}>
              {rank.name} · ⭐ {totalStars} total
            </span>
            <span style={{ fontSize: 16 }}>🏆</span>
          </div>
          <button className="press" onClick={() => pickDifficulty(difficulty)}
            style={{ ...bigBtn(meta.color, "rgba(0,0,0,.2)"), width: "100%", marginBottom: 10 }}>
            🔁 Try Again
          </button>
          <button className="press" onClick={goBack}
            style={{ ...bigBtn("#475569", "#334155"), width: "100%", marginBottom: 10 }}>
            Change Difficulty
          </button>
          <button className="press" onClick={goHome}
            style={{ ...bigBtn("#1e3a8a", "#15296b"), width: "100%" }}>
            🧢 Different Position
          </button>
        </div>
      </div>
    );
  }

  // ---- PLAY ----
  const meta = POS_META[position];
  const inReview = reviewIdx !== null;
  const viewSc = inReview ? queue[reviewIdx] : sc;
  // In review, force the revealed state so the correct answer + explanation show.
  const viewPhase = inReview ? "done" : phase;
  const viewResult = inReview ? "correct" : result;
  const canGoBack = (inReview ? reviewIdx : idx) > 0;

  return (
    <div style={page} onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}>
      <style>{styleSheet}</style>
      <div style={card}>
        <Header meta={meta} idx={inReview ? reviewIdx : idx} total={queue.length}
          goHome={goHome} soundOn={soundOn}
          toggleSound={() => { setSoundOn((s) => !s); stopSpeak(); }} />

        {/* Review banner */}
        {inReview && (
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between",
            background: "#fef9c3", border: "2px solid #f59e0b", borderRadius: 12,
            margin: "8px 14px 0", padding: "8px 12px" }}>
            <span style={{ fontSize: 13, fontWeight: 700, color: "#92400e" }}>
              👀 Looking back — Play {reviewIdx + 1}
            </span>
            <button onClick={exitReview} className="press"
              style={{ background: "#f59e0b", color: "#fff", border: "none", borderRadius: 9,
                padding: "5px 11px", fontSize: 13, fontWeight: 800, cursor: "pointer",
                fontFamily: "inherit", boxShadow: "0 2px 0 #b45309" }}>
              Back to game →
            </button>
          </div>
        )}

        <CoachBubble prompt={viewSc.prompt} mood={viewResult === "correct" ? "cheer" : "happy"} variant={viewSc.variant} />

        <div style={{ padding: "4px 12px 0" }}>
          <Field sc={viewSc} phase={viewPhase} chosen={inReview ? viewSc.correct : chosen} result={viewResult}
            choose={inReview ? (() => {}) : choose} movePos={movePos} showHit={showHit}
            ballPath={inReview ? null : ballPath} puff={inReview ? null : puff} batSwing={inReview ? 0 : batSwing}
            pitcherRun={inReview ? null : pitcherRun}
            stage={meta} position={position} />
        </div>

        {/* Swipe hint / back arrow — only when there's a prior play to review */}
        {!inReview && idx > 0 && (
          <div style={{ textAlign: "center", padding: "2px 0 0" }}>
            <button onClick={reviewPrev} className="press"
              style={{ background: "transparent", border: "none", color: "#94a3b8",
                fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: "inherit" }}>
              ← swipe to review past plays
            </button>
          </div>
        )}

        {inReview ? (
          <ReviewFeedback sc={viewSc} color={meta.color}
            canGoBack={canGoBack} onPrev={reviewPrev} onNext={reviewNext} />
        ) : (
          <Feedback sc={sc} phase={phase} result={result}
            next={next} tryAgain={tryAgain} color={meta.color}
            choose={choose}
            isLast={idx + 1 >= queue.length} />
        )}
      </div>
    </div>
  );
}

// ============================================================
// Subcomponents
// ============================================================
function Header({ meta, idx, total, goHome, soundOn, toggleSound }) {
  return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between",
      padding: "10px 12px", background: meta.color }}>
      <button onClick={goHome} style={{
        background: "rgba(255,255,255,.22)", color: "#fff", border: "none",
        fontSize: 15, fontWeight: 700, padding: "6px 12px", borderRadius: 12,
        cursor: "pointer", fontFamily: "inherit" }}>🏠</button>
      <div style={{ textAlign: "center", color: "#fff" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 6, fontWeight: 700, fontSize: 16, lineHeight: 1 }}>
          {meta.img
            ? <img src={meta.img} alt="" width={24} height={24}
                style={{ borderRadius: "50%", objectFit: "contain", background: "rgba(255,255,255,0.9)" }} />
            : <span>{meta.emoji}</span>}
          <span>{meta.name}</span>
        </div>
        <div style={{ display: "flex", gap: 4, justifyContent: "center", marginTop: 6 }}>
          {Array.from({ length: total }).map((_, i) => (
            <div key={i} style={{ width: 8, height: 8, borderRadius: 8,
              background: i < idx ? "#fff" : i === idx ? "#fde047" : "rgba(255,255,255,.4)" }} />
          ))}
        </div>
      </div>
      <button onClick={toggleSound} style={{
        background: "rgba(255,255,255,.22)", color: "#fff", border: "none",
        fontSize: 15, fontWeight: 700, padding: "6px 12px", borderRadius: 12,
        cursor: "pointer", fontFamily: "inherit" }}>
        {soundOn ? "🔊" : "🔇"}
      </button>
    </div>
  );
}

function CoachBubble({ prompt, mood, variant }) {
  const tag = variant === "hard" ? "💥 HIT HARD!" : variant === "soft" ? "🐢 SLOW ROLL" : null;
  const displayedPrompt = expandPositions(prompt);
  return (
    <div style={{ display: "flex", alignItems: "flex-start", gap: 9, padding: "12px 12px 4px" }}>
      <div style={{ flexShrink: 0, animation: "float 3s ease-in-out infinite" }}>
        <DragonCoach size={58} mood={mood} />
      </div>
      <div style={{ position: "relative", background: "#f1f5f9", borderRadius: 14,
        padding: "10px 12px", flex: 1, border: "2px solid #e2e8f0" }}>
        <div style={{ position: "absolute", left: -9, top: 16, width: 0, height: 0,
          borderTop: "8px solid transparent", borderBottom: "8px solid transparent",
          borderRight: "10px solid #f1f5f9" }} />
        {tag && (
          <div style={{ display: "inline-block", fontSize: 12, fontWeight: 700,
            background: variant === "hard" ? "#fee2e2" : "#fef3c7",
            color: variant === "hard" ? "#b91c1c" : "#a16207",
            padding: "2px 8px", borderRadius: 8, marginBottom: 5 }}>{tag}</div>
        )}
        <p style={{ margin: 0, fontSize: 15, fontWeight: 600, color: "#0f2747", lineHeight: 1.3 }}>{displayedPrompt}</p>
      </div>
    </div>
  );
}

function Field({ sc, phase, chosen, result, choose, movePos, showHit, ballPath, puff, batSwing, pitcherRun, stage, position }) {
  const fielders = new Set(["P","C","1B","2B","SS","3B","LF","CF","RF"]);
  const reveal = phase === "reveal" || phase === "rehearse" || phase === "rehearseMove" || phase === "done";
  const isPopup = sc.mode === "popup";
  const isBaserun = sc.mode === "baserun";
  const targets = sc.targets || [];
  const isRehearsing = phase === "rehearse";

  // Basepath safe-zone for pitcher backup
  const showBasepathLine = position === "P" && sc.mode === "cover" && ["LF","CF","RF"].includes(sc.ballAt);

  return (
    <svg viewBox="0 0 400 380" style={{ width: "100%", display: "block" }}>
      <defs>
        <linearGradient id="grass" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="#4ade80" />
          <stop offset="100%" stopColor="#22a84f" />
        </linearGradient>
      </defs>
      <rect width="400" height="380" fill="url(#grass)" />
      {[0,1,2,3,4].map(i => <rect key={i} x={i*80} y="0" width="40" height="380" fill="#3fce6f" opacity="0.45" />)}
      <polygon points="200,348 332,214 200,80 68,214" fill="#e0a96d" stroke="#c98a4c" strokeWidth="2" />
      <polygon points="200,300 286,214 200,128 114,214" fill="#34c46a" />
      <line x1="200" y1="330" x2="350" y2="180" stroke="#fff" strokeWidth="3" opacity="0.85" />
      <line x1="200" y1="330" x2="50" y2="180" stroke="#fff" strokeWidth="3" opacity="0.85" />
      <circle cx="200" cy="218" r="22" fill="#e0a96d" stroke="#c98a4c" strokeWidth="2" />

      {/* Special basepath safe-zone for pitcher backup */}
      {showBasepathLine && (
        <>
          <polyline points="316,214 200,98 84,214" fill="none" stroke="#facc15"
            strokeWidth="4" strokeDasharray="6 4" opacity="0.85" />
          <text x="200" y="65" textAnchor="middle" fontSize="11" fontWeight="700" fill="#a16207">
            Stay inside this line!
          </text>
        </>
      )}

      {/* Bases */}
      {BASES.map((b) => {
        const p = POS[b];
        const tappable = !sc.mc && phase === "ask" && targets.includes(b) && !isPopup;
        const correctArr = Array.isArray(sc.correct) ? sc.correct : [sc.correct];
        const isCorrect = (phase === "reveal" || phase === "rehearse" || phase === "rehearseMove" || phase === "done") && correctArr.includes(b);
        const isWrong = phase === "reveal" && b === chosen && result === "wrong";
        const fill = isCorrect ? "#22c55e" : isWrong ? "#f87171" : "#ffffff";
        return (
          <g key={b} onClick={() => tappable && choose(b)} style={{ cursor: tappable ? "pointer" : "default" }}>
            <circle cx={p.x} cy={p.y} r="28" fill="transparent" />
            {tappable && (
              <circle cx={p.x} cy={p.y} r="20" fill="none" stroke={stage.color} strokeWidth="3"
                opacity="0.9" style={{ transformOrigin: `${p.x}px ${p.y}px`, animation: "pulse 1.3s ease-in-out infinite" }} />
            )}
            {b === "home" ? (
              <polygon points={`${p.x-12},${p.y-6} ${p.x+12},${p.y-6} ${p.x+12},${p.y+4} ${p.x},${p.y+13} ${p.x-12},${p.y+4}`}
                fill={fill} stroke="#94a3b8" strokeWidth="2" />
            ) : (
              <rect x={p.x-12} y={p.y-12} width="24" height="24" rx="5"
                transform={`rotate(45 ${p.x} ${p.y})`} fill={fill} stroke="#94a3b8" strokeWidth="2" />
            )}
            {isCorrect && <text x={p.x} y={p.y+5} textAnchor="middle" fontSize="16" fontWeight="800" fill="#fff">✓</text>}
          </g>
        );
      })}

      {/* Runners */}
      {sc.baseSit && RUNNERS[sc.baseSit]?.map(b => <Runner key={b} x={POS[b].x} y={POS[b].y} base={b} />)}

      {/* Base-running mode: the YOU runner at the starting base */}
      {isBaserun && sc.runnerAt && (
        <g>
          {/* Highlight the runner's current base */}
          <circle cx={POS[sc.runnerAt].x} cy={POS[sc.runnerAt].y} r="22" fill="none"
            stroke="#db2777" strokeWidth="3" opacity="0.7"
            style={{ transformOrigin: `${POS[sc.runnerAt].x}px ${POS[sc.runnerAt].y}px`,
              animation: "pulse 1.6s ease-in-out infinite" }} />
          <Runner x={POS[sc.runnerAt].x + 4} y={POS[sc.runnerAt].y} base={sc.runnerAt} />
          <text x={POS[sc.runnerAt].x} y={POS[sc.runnerAt].y - 30} textAnchor="middle"
            fontSize="12" fontWeight="800" fill="#db2777">YOU</text>
        </g>
      )}

      {/* Fielders */}
      {[...fielders].map((f) => {
        const p = displayedPos(f, sc);
        const isYou = (sc.mode === "throw" || sc.mode === "field") && f === sc.ballAt;
        const isCoverYou = sc.mode === "cover" && f === sc.you;
        const isBallAt = (sc.mode === "cover") && f === sc.ballAt;
        // MC mode: no field fielders are tappable — the choice is via buttons below
        const tappable = !sc.mc && phase === "ask" && targets.includes(f);
        const correctArr = Array.isArray(sc.correct) ? sc.correct : [sc.correct];
        const isCorrect = (phase === "reveal" || phase === "done") && correctArr.includes(f);
        const isWrong = phase === "reveal" && f === chosen && result === "wrong";
        const isPopupCandidate = isPopup && (sc.candidates || []).includes(f);

        // During rehearse phase, the PITCHER is the tappable target —
        // EXCEPT in the pitcher's own module, where the BALL is tapped instead.
        const isRehearseTarget = isRehearsing && f === "P" && sc.position !== "P";

        // Visual: tappable popup candidates always pulse
        const showPulse = tappable || (isPopup && isPopupCandidate && phase === "ask") || isRehearseTarget;

        // Highlight pitcher in green during rehearseMove/done if they got it right
        const isRehearseGlow = (phase === "rehearseMove" || phase === "done") && f === "P" && needsRehearseForSc(sc);

        const fillC = isCorrect ? "#22c55e"
          : isWrong ? "#ef4444"
          : isRehearseTarget ? "#dc2626"
          : isRehearseGlow ? "#22c55e"
          : isYou ? "#2563eb"
          : isCoverYou ? "#2563eb"
          : isBallAt ? "#f97316"
          : "#475569";
        const big = isYou || isCoverYou || isBallAt || tappable || isCorrect || isWrong || isPopupCandidate || isRehearseTarget || isRehearseGlow;
        const r = big ? 16 : 12;

        const clickable = tappable || (isPopup && isPopupCandidate && phase === "ask") || isRehearseTarget;

        return (
          <g key={f}
            onClick={() => clickable && choose(f)}
            style={{ cursor: clickable ? "pointer" : "default" }}>
            {clickable && <circle cx={p.x} cy={p.y} r="26" fill="transparent" />}
            {showPulse && (
              <circle cx={p.x} cy={p.y} r="23" fill="none" stroke={isRehearseTarget ? "#dc2626" : stage.color} strokeWidth="3"
                opacity="0.9" style={{ transformOrigin: `${p.x}px ${p.y}px`, animation: "pulse 1.3s ease-in-out infinite" }} />
            )}
            <circle cx={p.x} cy={p.y} r={r} fill={fillC} stroke="#fff" strokeWidth="2.5" />
            <text x={p.x} y={p.y+4} textAnchor="middle"
              fontSize={r > 13 ? 11 : 9} fontWeight="800" fill="#fff">
              {isCorrect && !isPopup ? "✓" : f}
            </text>
            {(isYou || isCoverYou) && (
              <text x={p.x} y={p.y - r - 4} textAnchor="middle" fontSize="11" fontWeight="700" fill="#1e3a8a">YOU</text>
            )}
            {isRehearseTarget && (
              <text x={p.x} y={p.y - r - 4} textAnchor="middle" fontSize="11" fontWeight="800" fill="#dc2626">TAP!</text>
            )}
          </g>
        );
      })}

      {/* Popup ball icon */}
      {isPopup && (
        <g>
          <circle cx={sc.popupAt.x} cy={sc.popupAt.y - 6} r="11" fill="#fff" stroke="#cbd5e1" strokeWidth="2" />
          <path d={`M${sc.popupAt.x-5} ${sc.popupAt.y-11} Q${sc.popupAt.x-9} ${sc.popupAt.y-6} ${sc.popupAt.x-5} ${sc.popupAt.y-1} M${sc.popupAt.x+5} ${sc.popupAt.y-11} Q${sc.popupAt.x+9} ${sc.popupAt.y-6} ${sc.popupAt.x+5} ${sc.popupAt.y-1}`}
            stroke="#ef4444" strokeWidth="1.5" fill="none" />
          <path d={`M${sc.popupAt.x} ${sc.popupAt.y+5} L${sc.popupAt.x-4} ${sc.popupAt.y+18} L${sc.popupAt.x+4} ${sc.popupAt.y+18} Z`}
            fill="rgba(0,0,0,0.18)" />
          <text x={sc.popupAt.x} y={sc.popupAt.y - 20} textAnchor="middle" fontSize="13" fontWeight="800" fill="#dc2626">↑POP!</text>
        </g>
      )}

      {/* CINEMATIC BALL ANIMATION */}
      {!isPopup && !isBaserun && (
        <>
          <BatSwing show={batSwing > 0} key={`bat-${batSwing}`} />
          <AnimatedBall path={ballPath} />
          {puff && <LandingPuff key={puff.key} x={puff.x} y={puff.y} show={true} />}
          <RunningPitcher run={pitcherRun} />
        </>
      )}

      {/* PITCHER rehearse: the ball at the base is the tap target */}
      {sc.position === "P" && isRehearsing && (() => {
        const ck = Array.isArray(sc.correct) ? sc.correct[0] : sc.correct;
        const bp = displayedPos(ck, sc) || POS[ck] || POS[sc.ballAt];
        if (!bp) return null;
        return (
          <g onClick={() => choose("BALL")} style={{ cursor: "pointer" }}>
            <circle cx={bp.x} cy={bp.y} r="26" fill="transparent" />
            <circle cx={bp.x} cy={bp.y} r="22" fill="none" stroke="#dc2626" strokeWidth="3"
              opacity="0.9" style={{ transformOrigin: `${bp.x}px ${bp.y}px`, animation: "pulse 1.3s ease-in-out infinite" }} />
            <circle cx={bp.x} cy={bp.y} r="10" fill="#fff" stroke="#1e293b" strokeWidth="1.5" />
            <path d={`M${bp.x-4} ${bp.y-5} Q${bp.x-7} ${bp.y} ${bp.x-4} ${bp.y+5} M${bp.x+4} ${bp.y-5} Q${bp.x+7} ${bp.y} ${bp.x+4} ${bp.y+5}`}
              stroke="#dc2626" strokeWidth="1.5" fill="none" />
            <text x={bp.x} y={bp.y - 28} textAnchor="middle" fontSize="11" fontWeight="800" fill="#dc2626">TAP!</text>
          </g>
        );
      })()}

      {/* OUT! callout — shows on correct answer (SAFE! for base running) */}
      {(phase === "reveal" || phase === "done") && result === "correct" && !isPopup && (
        <g key={`out-${sc.id || idx}`} style={{ pointerEvents: "none" }}>
          <rect x={isBaserun ? 110 : 120} y="155" width={isBaserun ? 180 : 160} height="60" rx="14"
            fill={isBaserun ? "#22c55e" : "#fbbf24"} stroke={isBaserun ? "#15803d" : "#92400e"} strokeWidth="4"
            style={{ animation: "outpop 0.6s cubic-bezier(.34,2,.64,1)" }} />
          <text x="200" y="195" textAnchor="middle" fontSize="38" fontWeight="900"
            fill={isBaserun ? "#fff" : "#7c2d12"} stroke="#fff" strokeWidth={isBaserun ? 0 : 1.5} paintOrder="stroke"
            style={{ animation: "outpop 0.6s cubic-bezier(.34,2,.64,1)" }}>
            {isBaserun ? "SAFE!" : "OUT!"}
          </text>
        </g>
      )}
      {/* Done state for infield rehearse — show "PLAY STOPPED!" */}
      {phase === "done" && needsRehearseForSc(sc) && result === "correct" && (
        <g style={{ pointerEvents: "none" }}>
          <text x="200" y="60" textAnchor="middle" fontSize="20" fontWeight="900"
            fill="#15803d" stroke="#fff" strokeWidth="2.5" paintOrder="stroke"
            style={{ animation: "outpop 0.5s cubic-bezier(.34,2,.64,1)" }}>
            ⚾ PLAY STOPPED!
          </text>
        </g>
      )}
    </svg>
  );
}

// Buttons component removed — tap-on-field is the only answer mechanic.
// Showing all targets as buttons revealed the wrong answers next to the right one.

function ReviewFeedback({ sc, color, canGoBack, onPrev, onNext }) {
  // Read-only summary of a previously answered question: shows the correct
  // answer (if MC) and the explanation, with back/forward navigation.
  const correctLabel = sc.mc ? (sc.mc.find((o) => o.correct) || {}).label : null;
  return (
    <div style={{ padding: "10px 14px 16px" }}>
      {correctLabel && (
        <div style={{ background: "#dcfce7", border: "2px solid #22c55e", borderRadius: 12,
          padding: "10px 12px", marginBottom: 10 }}>
          <div style={{ fontSize: 12, fontWeight: 800, color: "#15803d", marginBottom: 2 }}>✅ Correct answer</div>
          <div style={{ fontSize: 14, fontWeight: 600, color: "#0f2747", lineHeight: 1.3 }}>{correctLabel}</div>
        </div>
      )}
      <div style={{ background: "#f0fdf4", border: "2px solid #86efac", borderRadius: 12, padding: "10px 12px" }}>
        <div style={{ fontSize: 14, color: "#166534", fontWeight: 500, lineHeight: 1.4 }}>
          {expandPositions(sc.why)}
        </div>
      </div>
      <div style={{ display: "flex", gap: 10, marginTop: 12 }}>
        <button onClick={onPrev} disabled={!canGoBack} className="press"
          style={{ flex: 1, background: canGoBack ? "#fff" : "#f1f5f9",
            border: `3px solid ${canGoBack ? color : "#cbd5e1"}`, borderRadius: 14,
            padding: "11px", fontSize: 15, fontWeight: 800,
            color: canGoBack ? color : "#94a3b8", cursor: canGoBack ? "pointer" : "default",
            fontFamily: "inherit", boxShadow: canGoBack ? `0 4px 0 ${color}` : "none" }}>
          ← Previous
        </button>
        <button onClick={onNext} className="press"
          style={{ flex: 1, background: color, border: "none", borderRadius: 14,
            padding: "11px", fontSize: 15, fontWeight: 800, color: "#fff",
            cursor: "pointer", fontFamily: "inherit", boxShadow: "0 4px 0 rgba(0,0,0,0.18)" }}>
          Next →
        </button>
      </div>
    </div>
  );
}

function Feedback({ sc, phase, result, next, tryAgain, color, isLast, choose }) {
  if (phase === "ask") {
    // MC mode: render multiple-choice buttons
    if (sc.mc) {
      return (
        <div style={{ padding: "10px 14px 14px" }}>
          <div style={{ textAlign: "center", fontSize: 13, fontWeight: 700,
            color: color, padding: "0 0 8px" }}>
            👆 Pick the best answer
          </div>
          {sc.mc.map((opt, i) => (
            <button key={i} onClick={() => choose(i)} className="press"
              style={{ display: "block", width: "100%", textAlign: "left",
                background: "#fff", border: `3px solid ${color}`,
                borderRadius: 14, padding: "11px 13px", marginBottom: 8,
                cursor: "pointer", fontFamily: "inherit",
                fontSize: 14, fontWeight: 600, color: "#0f2747", lineHeight: 1.3,
                boxShadow: `0 4px 0 ${color}`,
                WebkitTapHighlightColor: "transparent" }}>
              {opt.label}
            </button>
          ))}
        </div>
      );
    }
    return (
      <div style={{ textAlign: "center", fontSize: 14, fontWeight: 700,
        color: color, padding: "10px 0 14px" }}>
        👆 Tap a glowing spot on the field!
      </div>
    );
  }

  if (phase === "move") return <div style={{ height: 14 }} />;

  // Rehearse phase: kid needs to tap the pitcher
  if (phase === "rehearse") {
    const isPitcher = sc.position === "P";
    return (
      <div style={{ padding: "8px 14px 18px", animation: "pop 0.35s ease" }}>
        <div style={{ background: "#fee2e2", border: "2px solid #dc2626",
          borderRadius: 14, padding: "11px 12px", marginBottom: 6 }}>
          <div style={{ fontSize: 17, fontWeight: 700, color: "#991b1b" }}>
            {isPitcher ? "⚾ Now go get the ball!" : "⚾ Now give it to the pitcher!"}
          </div>
          <div style={{ fontSize: 14, color: "#7f1d1d", marginTop: 3, fontWeight: 500, lineHeight: 1.35 }}>
            {isPitcher
              ? "The pitcher must be near the ball in the infield to STOP the play. Tap the BALL — the pitcher will run over and get it!"
              : "The pitcher needs the ball in the infield to STOP the play. Tap the pitcher!"}
          </div>
        </div>
      </div>
    );
  }

  if (phase === "rehearseMove") {
    return <div style={{ height: 64 }} />;
  }

  // Reveal phase: show feedback but no Next button yet if rehearse will follow
  if (phase === "reveal") {
    if (result === "correct") {
      return (
        <div style={{ padding: "8px 14px 12px", animation: "pop 0.35s ease" }}>
          <div style={{ background: "#dcfce7", border: "2px solid #22c55e",
            borderRadius: 14, padding: "11px 12px" }}>
            <div style={{ fontSize: 17, fontWeight: 700, color: "#15803d" }}>✅ Right!</div>
            <div style={{ fontSize: 14, color: "#166534", marginTop: 3, fontWeight: 500, lineHeight: 1.35 }}>{expandPositions(sc.why)}</div>
          </div>
        </div>
      );
    }
    // Wrong answer — show try again
    return (
      <div style={{ padding: "8px 14px 18px", animation: "shake 0.4s ease" }}>
        <div style={{ background: "#fef3c7", border: "2px solid #f59e0b",
          borderRadius: 14, padding: "11px 12px", marginBottom: 10 }}>
          <div style={{ fontSize: 17, fontWeight: 700, color: "#b45309" }}>🤔 Not quite!</div>
          <div style={{ fontSize: 14, color: "#92400e", marginTop: 3, fontWeight: 500, lineHeight: 1.35 }}>{expandPositions(sc.hint)}</div>
        </div>
        <button onClick={tryAgain} className="press"
          style={{ background: "#f59e0b", color: "#fff", border: "none", fontFamily: "inherit",
            fontWeight: 700, fontSize: 17, padding: "12px 20px", borderRadius: 14,
            width: "100%", cursor: "pointer", boxShadow: "0 5px 0 #b45309",
            WebkitTapHighlightColor: "transparent" }}>
          Try Again 🔁
        </button>
      </div>
    );
  }

  // phase === "done" — show Next button (after rehearse, or for plays that skip rehearse)
  return (
    <div style={{ padding: "8px 14px 18px", animation: "pop 0.35s ease" }}>
      <div style={{ background: "#dcfce7", border: "2px solid #22c55e",
        borderRadius: 14, padding: "11px 12px", marginBottom: 10 }}>
        <div style={{ fontSize: 17, fontWeight: 700, color: "#15803d" }}>
          {needsRehearseForSc(sc) ? "🎯 Play stopped — well done!" : "✅ Right!"}
        </div>
        <div style={{ fontSize: 14, color: "#166534", marginTop: 3, fontWeight: 500, lineHeight: 1.35 }}>
          {needsRehearseForSc(sc) ? "Pitcher has the ball in the infield. " + expandPositions(sc.why) : expandPositions(sc.why)}
        </div>
      </div>
      <button onClick={next} className="press"
        style={{ background: color, color: "#fff", border: "none", fontFamily: "inherit",
          fontWeight: 700, fontSize: 17, padding: "12px 20px", borderRadius: 14,
          width: "100%", cursor: "pointer", boxShadow: "0 5px 0 rgba(0,0,0,.2)",
          WebkitTapHighlightColor: "transparent" }}>
        {isLast ? "Finish! 🎉" : "Next Play →"}
      </button>
    </div>
  );
}

const styleSheet = `
@import url('https://fonts.googleapis.com/css2?family=Fredoka:wght@400;500;600;700&display=swap');
* { box-sizing: border-box; }
html, body, #root { height: 100%; margin: 0; }
@keyframes pulse { 0%,100% { transform: scale(1); opacity:.9 } 50% { transform: scale(1.28); opacity:.35 } }
@keyframes float { 0%,100% { transform: translateY(0) } 50% { transform: translateY(-7px) } }
@keyframes pop { 0% { transform: scale(.7); opacity:0 } 60% { transform: scale(1.06) } 100% { transform: scale(1); opacity:1 } }
@keyframes shake { 0%,100%{transform:translateX(0)} 20%{transform:translateX(-7px)} 40%{transform:translateX(7px)} 60%{transform:translateX(-5px)} 80%{transform:translateX(5px)} }
@keyframes outpop { 0% { transform: scale(.3) rotate(-12deg); opacity: 0 } 50% { transform: scale(1.18) rotate(4deg); opacity: 1 } 80% { transform: scale(1) rotate(-2deg); opacity: 1 } 100% { transform: scale(1) rotate(0deg); opacity: 1 } }
.press:active { transform: translateY(3px); box-shadow: none !important; }
button { -webkit-tap-highlight-color: transparent; }
`;
